function ngayHomQuaCua(dateStr) {
  const d = new Date(dateStr + "T00:00:00");
  d.setDate(d.getDate() - 1);
  return d.toISOString().slice(0, 10);
}

function capNhatStreak(tk, homNay) {
  if (tk.ngayStreakGanNhat === homNay) return tk;
  const lienTiep = tk.ngayStreakGanNhat === ngayHomQuaCua(homNay);
  const streakMoi = lienTiep ? tk.streakHienTai + 1 : 1;
  return {
    ...tk,
    streakHienTai: streakMoi,
    streakCaoNhat: Math.max(tk.streakCaoNhat, streakMoi),
    ngayStreakGanNhat: homNay,
  };
}

function tinhHuyHieuMoi(tkCu, tkMoi) {
  return BADGE_LIST.filter((b) => !tkCu.huyHieuMoKhoa.includes(b.id) && b.dat(tkMoi)).map((b) => b.id);
}

function uid() {
  return Math.random().toString(36).slice(2, 10) + Date.now().toString(36);
}

function dinhDangGio(s) {
  const m = Math.floor(s / 60).toString().padStart(2, "0");
  const gg = Math.floor(s % 60).toString().padStart(2, "0");
  return `${m}:${gg}`;
}

// Âm thanh nhẹ báo hết phiên (2 nốt chuông), im lặng nếu trình duyệt không hỗ trợ
function phatAmBaoXongPhien() {
  try {
    const Ctx = window.AudioContext || window.webkitAudioContext;
    const ctx = new Ctx();
    const now = ctx.currentTime;
    [523.25, 659.25].forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = "sine";
      osc.frequency.value = freq;
      const batDau = now + i * 0.16;
      gain.gain.setValueAtTime(0.0001, batDau);
      gain.gain.exponentialRampToValueAtTime(0.16, batDau + 0.02);
      gain.gain.exponentialRampToValueAtTime(0.0001, batDau + 0.45);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start(batDau);
      osc.stop(batDau + 0.5);
    });
  } catch (e) {
    // trình duyệt không hỗ trợ Web Audio, bỏ qua
  }
}

// ---------- Âm thanh nhẹ dùng chung ----------
let _audioCtx = null;
function layAudioContext() {
  try {
    if (!_audioCtx) {
      const Ctx = window.AudioContext || window.webkitAudioContext;
      _audioCtx = new Ctx();
    }
    if (_audioCtx.state === "suspended") _audioCtx.resume();
    return _audioCtx;
  } catch (e) {
    return null;
  }
}

function phatTiengNgan(freq, thoiLuong = 0.12, loai = "sine", amLuong = 0.1, doTre = 0) {
  try {
    const ctx = layAudioContext();
    if (!ctx) return;
    const now = ctx.currentTime + doTre;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = loai;
    osc.frequency.value = freq;
    gain.gain.setValueAtTime(0.0001, now);
    gain.gain.exponentialRampToValueAtTime(amLuong, now + 0.012);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + thoiLuong);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(now);
    osc.stop(now + thoiLuong + 0.03);
  } catch (e) {
    // im lặng nếu trình duyệt không hỗ trợ
  }
}

function amTick() { phatTiengNgan(620, 0.06, "sine", 0.06); }
function amChonChip() { phatTiengNgan(520, 0.07, "sine", 0.06); }
function amBatDauPhien() {
  phatTiengNgan(440, 0.09, "sine", 0.07);
  phatTiengNgan(660, 0.12, "sine", 0.07, 0.08);
}
function amHaGucBoss() {
  [392, 494, 587, 784].forEach((f, i) => phatTiengNgan(f, 0.17, "sine", 0.1, i * 0.09));
}

function amDonSachNgay() {
  [523, 659, 784, 988, 1175].forEach((f, i) => phatTiengNgan(f, 0.2, "sine", 0.1, i * 0.08));
}

function amMoHuyHieu() {
  phatTiengNgan(700, 0.09, "sine", 0.08);
  phatTiengNgan(1050, 0.14, "sine", 0.09, 0.1);
}

function amVoTay() {
  try {
    const ctx = layAudioContext();
    if (!ctx) return;
    const now = ctx.currentTime;
    const soTieng = 5;
    for (let i = 0; i < soTieng; i++) {
      const t = now + i * 0.085 + Math.random() * 0.02;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = "square";
      osc.frequency.value = 1600 + Math.random() * 700;
      gain.gain.setValueAtTime(0.0001, t);
      gain.gain.exponentialRampToValueAtTime(0.055, t + 0.006);
      gain.gain.exponentialRampToValueAtTime(0.0001, t + 0.055);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start(t);
      osc.stop(t + 0.07);
    }
    // thêm chuông vui phía sau tiếng vỗ tay
    phatTiengNgan(660, 0.1, "sine", 0.08, 0.34);
    phatTiengNgan(880, 0.14, "sine", 0.08, 0.42);
  } catch (e) {
    // im lặng nếu trình duyệt không hỗ trợ
  }
}

function amBongNo() {
  try {
    const ctx = layAudioContext();
    if (!ctx) return;
    const now = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = "triangle";
    osc.frequency.setValueAtTime(900 + Math.random() * 220, now);
    osc.frequency.exponentialRampToValueAtTime(110, now + 0.1);
    gain.gain.setValueAtTime(0.15, now);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.12);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(now);
    osc.stop(now + 0.14);
  } catch (e) {
    // im lặng nếu trình duyệt không hỗ trợ
  }
}
