// ---------- Các khu vực chơi (mini game) ----------
const BONG_ANH = [IMG_BONG_XANHDUONG, IMG_BONG_BAC, IMG_BONG_VANG, IMG_BONG_HONG, IMG_BONG_DO];

function BongBongArea({ onDiem }) {
  const [bongs, setBongs] = useState([]);

  useEffect(() => {
    const spawnId = setInterval(() => {
      setBongs((cur) => {
        if (cur.length >= 6) return cur;
        const id = uid();
        const size = 46 + Math.random() * 38;
        const anh = BONG_ANH[Math.floor(Math.random() * BONG_ANH.length)];
        return [
          ...cur,
          {
            id,
            size,
            anh,
            left: Math.random() * (100 - size / 3.6),
            top: Math.random() * (100 - size / 3.6),
          },
        ];
      });
    }, 550);
    return () => clearInterval(spawnId);
  }, []);

  function dapBong(id) {
    setBongs((cur) => cur.filter((b) => b.id !== id));
    amBongNo();
    onDiem();
  }

  return (
    <div className="game-area bongbong-area">
      {bongs.map((b) => (
        <button
          key={b.id}
          onClick={() => dapBong(b.id)}
          aria-label="Đập bong bóng"
          className="bong-real"
          style={{ width: b.size, height: b.size * 1.25, left: `${b.left}%`, top: `${b.top}%` }}
        >
          <img src={b.anh} alt="" className="bong-img" />
        </button>
      ))}
    </div>
  );
}

function ChoCuiArea({ onDiem }) {
  const [nhat, setNhat] = useState(0); // 0,1,2 dùng để hiện vết nứt trên khúc hiện tại
  const [dangVo, setDangVo] = useState(false);
  const [dam, setDam] = useState([]); // dăm gỗ văng ra
  const [logKey, setLogKey] = useState(0);
  const timeoutRef = useRef(null);
  const soNhatRef = useRef(0); // đếm tổng số nhát, không giới hạn

  function chem() {
    // không chặn click — muốn chẻ bao nhiêu nhát cũng được
    const idDam = uid();
    const goc = -55 + Math.random() * 110;
    setDam((c) => [...c, { id: idDam, goc }]);
    setTimeout(() => setDam((c) => c.filter((d) => d.id !== idDam)), 480);

    amChem();
    onDiem(); // mỗi nhát đều tính điểm

    soNhatRef.current += 1;
    const trongChu = soNhatRef.current % 3;
    if (trongChu === 0) {
      amVoCui();
      setDangVo(true);
      clearTimeout(timeoutRef.current);
      timeoutRef.current = setTimeout(() => {
        setDangVo(false);
        setNhat(0);
        setLogKey((k) => k + 1);
      }, 480);
    } else {
      setNhat(trongChu);
    }
  }

  useEffect(() => () => clearTimeout(timeoutRef.current), []);

  return (
    <div className="game-area chocui-area" onClick={chem} role="button" aria-label="Chạm để chẻ củi">
      <div className="chocui-stage">
        <img src={IMG_STUMP} alt="Gốc cây" className="stump-img" />

        {!dangVo ? (
          <div key={logKey} className="log-img-wrap">
            <img src={IMG_LOG} alt="Khúc gỗ" className="log-img" />
            {nhat >= 1 && <span className="vet-nut vet-nut-1" />}
            {nhat >= 2 && <span className="vet-nut vet-nut-2" />}
          </div>
        ) : (
          <div className="log-img-wrap">
            <img src={IMG_LOG} alt="" className="log-img log-half log-half-left" style={{ clipPath: "inset(0 50% 0 0)" }} />
            <img src={IMG_LOG} alt="" className="log-img log-half log-half-right" style={{ clipPath: "inset(0 0 0 50%)" }} />
          </div>
        )}
      </div>

      {dam.map((d) => (
        <span key={d.id} className="wood-chip" style={{ transform: `translate(-50%,-50%) rotate(${d.goc}deg)` }} />
      ))}
      <span className="chocui-hint">Chạm vào khúc gỗ để chẻ</span>
    </div>
  );
}

const FRUIT_IMG = { cam: IMG_CAM, dua: IMG_SAURIENG, tao: IMG_TAO };

function CatTraiCayArea({ onDiem }) {
  const [fruits, setFruits] = useState([]);
  const [gioX, setGioX] = useState(50); // vị trí giỏ theo %, 0-100
  const [noBom, setNoBom] = useState(false);
  const areaRef = useRef(null);
  const LOAI = ["cam", "dua", "tao", "cam", "dua", "tao", "bom"]; // bom hiếm hơn (1/7)

  // rơi trái cây mới
  useEffect(() => {
    const spawnId = setInterval(() => {
      setFruits((cur) => {
        if (cur.length >= 5) return cur;
        const id = uid();
        const loai = LOAI[Math.floor(Math.random() * LOAI.length)];
        const left = 10 + Math.random() * 76;
        const thoiGianRoi = 2400 + Math.random() * 1300;
        return [...cur, { id, loai, left, thoiGianRoi, batDau: Date.now() }];
      });
    }, 700);
    return () => clearInterval(spawnId);
  }, []);

  // kiểm tra bắt trúng giỏ / rơi trượt (không trừ điểm nếu trượt hoặc trúng bom)
  useEffect(() => {
    const checkId = setInterval(() => {
      setFruits((cur) => {
        let doiThay = false;
        const conLai = [];
        for (const f of cur) {
          const troi = (Date.now() - f.batDau) / f.thoiGianRoi;
          if (troi >= 0.78 && troi <= 0.95 && Math.abs(f.left - gioX) <= 13) {
            if (f.loai === "bom") {
              amTrungBom();
              setNoBom(true);
              setTimeout(() => setNoBom(false), 420);
            } else {
              amBatTrai();
              onDiem();
            }
            doiThay = true;
            continue;
          }
          if (troi > 0.97) {
            doiThay = true;
            continue;
          }
          conLai.push(f);
        }
        return doiThay ? conLai : cur;
      });
    }, 90);
    return () => clearInterval(checkId);
  }, [gioX, onDiem]);

  function diChuyenGio(clientX) {
    if (!areaRef.current) return;
    const rect = areaRef.current.getBoundingClientRect();
    const pct = ((clientX - rect.left) / rect.width) * 100;
    setGioX(Math.max(7, Math.min(93, pct)));
  }

  return (
    <div
      ref={areaRef}
      className={`fruit-area ${noBom ? "no-bom" : ""}`}
      onPointerDown={(e) => diChuyenGio(e.clientX)}
      onPointerMove={(e) => diChuyenGio(e.clientX)}
    >
      {fruits.map((f) => (
        <div
          key={f.id}
          className={`fruit-fall ${f.loai === "bom" ? "fruit-bom" : ""}`}
          style={{ left: `${f.left}%`, animationDuration: `${f.thoiGianRoi}ms` }}
        >
          <img src={f.loai === "bom" ? IMG_BOM : FRUIT_IMG[f.loai]} alt="" className="fruit-img" />
        </div>
      ))}
      <div className="gio-hung" style={{ left: `${gioX}%` }}>
        <img src={IMG_BASKET} alt="Giỏ hứng" className="gio-img" />
      </div>
      {noBom && <span className="bom-toast">💥 Coi chừng bom!</span>}
      <span className="gio-hint">Rê chuột hoặc kéo ngón tay để di chuyển giỏ — né trái bom nhé</span>
    </div>
  );
}

